{
  "uiTreePath": ".arkpilot/designs/ui-tree.json",
  "app": {
    "name": "手作·印记",
    "tagline": "温润手作 · 记录成长",
    "dataStrategy": "local-first, single-studio, no remote backend. First launch = empty state. All HTML sample data is decorative only and is NOT seeded. Persistence via @kit.ArkData preferences (JSON-serialized arrays).",
    "persistenceKeys": {
      "members": "shouzuo.members",
      "works": "shouzuo.works",
      "pointsRecords": "shouzuo.points",
      "courses": "shouzuo.courses",
      "inventory": "shouzuo.inventory",
      "inventoryRecords": "shouzuo.inventoryRecords",
      "settings": "shouzuo.settings",
      "seq": "shouzuo.seq"
    }
  },
  "dataModel": {
    "entities": {
      "Member": {
        "fields": {
          "id": "string",
          "name": "string",
          "phone": "string",
          "birthday": "string (YYYY-MM-DD, optional)",
          "level": "MemberLevel = 'new'|'silver'|'gold'|'platinum'",
          "note": "string",
          "crafts": "string[] (craft names)",
          "points": "number",
          "lastVisitAt": "number (ms, 0 if never)",
          "remindedAt": "number (ms, 0 if never reminded)",
          "createdAt": "number (ms)"
        },
        "invariants": "points >= 0; points always equals last PointsRecord.balanceAfter for that member (or 0 if no records)."
      },
      "WorkPhoto": {
        "fields": { "id": "string", "memberId": "string", "path": "string", "note": "string", "createdAt": "number" }
      },
      "PointsRecord": {
        "fields": {
          "id": "string",
          "memberId": "string",
          "delta": "number (+/-)",
          "balanceAfter": "number",
          "type": "PointsType = 'checkin'|'consume'|'adjust'|'course'|'redeem'",
          "amount": "number (yuan spent, 0 if N/A)",
          "note": "string",
          "createdAt": "number"
        }
      },
      "Course": {
        "fields": {
          "id": "string",
          "title": "string",
          "date": "string (YYYY-MM-DD)",
          "startTime": "string (HH:mm)",
          "durationMin": "number",
          "capacity": "number",
          "bookedMemberIds": "string[]",
          "materialLinks": "CourseMaterial[]",
          "status": "CourseStatus = 'open'|'full'|'cancelled'|'finished'",
          "note": "string"
        },
        "derived": "status==='full' iff bookedMemberIds.length===capacity; status==='open' when <capacity and not cancelled/finished."
      },
      "CourseMaterial": { "fields": { "itemId": "string", "quantity": "number (>0)" } },
      "InventoryItem": {
        "fields": { "id": "string", "name": "string", "unit": "string", "stock": "number", "threshold": "number", "createdAt": "number" }
      },
      "InventoryRecord": {
        "fields": { "id": "string", "itemId": "string", "delta": "number (-consume/+restock)", "stockAfter": "number", "reason": "string", "refType": "'course'|'consume'|'restock'|'manual'", "refId": "string", "createdAt": "number" }
      },
      "Settings": {
        "fields": { "studioName": "string", "pointsPerCheckin": "number", "pointsPerYuan": "number", "dormantThresholdDays": "number" },
        "defaults": { "studioName": "我的手作工作室", "pointsPerCheckin": 10, "pointsPerYuan": 1, "dormantThresholdDays": 60 }
      }
    },
    "formState": {
      "MemberForm": "editable draft for member-edit-page: id?(empty=create), name, phone, birthday, level, note, crafts[], works[](upload staging)"
    },
    "computedState": {
      "dormantMembers": "members where (now - lastVisitAt) > dormantThresholdDays*86400000 AND lastVisitAt>0",
      "todayCourses": "courses where date === today",
      "courseCapacity": "{ booked: bookedMemberIds.length, capacity, remaining: capacity-booked }",
      "memberHistory": "PointsRecords for member sorted desc by createdAt",
      "inventoryLow": "items where stock <= threshold"
    }
  },
  "services": {
    "DataStore": "singleton holding all entity arrays + Settings; load()/persist() via preferences; nextId(prefix) sequence; initialized with UIAbility context.",
    "MemberService": "create/update/delete member; add/remove craft; add work photo; list/search/filter-by-craft.",
    "PointsService": "checkin(memberId) += pointsPerCheckin; consume(memberId, yuan) += floor(yuan*pointsPerYuan); adjust(memberId, delta, note); each writes a PointsRecord and updates member.points + lastVisitAt (checkin/consume).",
    "CourseService": "create/update/delete course; book(courseId,memberId) — capacity guard, push to bookedMemberIds, deduct linked materials once (per booking) via InventoryService; cancel(courseId,memberId) — remove from roster (no auto-restock in this phase); list by date; month/week/day calendar days.",
    "InventoryService": "create/update item; restock(itemId, qty, reason); deduct(itemId, qty, refType, refId, reason) — never below 0 (floor at 0, record delta as actual applied); records(itemId) history; search.",
    "DormantService": "detect(thresholdDays) list; remind(memberId) sets remindedAt=now; threshold config from Settings.",
    "SettingsService": "get/update Settings (studioName, pointsPerCheckin, pointsPerYuan, dormantThresholdDays)."
  },
  "stateMachine": {
    "courseBooking": {
      "states": ["available", "full", "booked-by-self", "cancelled"],
      "transitions": {
        "book-course": "available|full-if-already-in-roster -> booked-by-self (if capacity allows) ; available->booked-by-self decrements remaining; when remaining hits 0 course becomes full",
        "cancel-course": "booked-by-self -> available (removes from roster); was-full -> open"
      },
      "errors": ["capacity-exceeded: cannot book when bookedMemberIds.length>=capacity", "already-booked: member already in roster"]
    },
    "memberEdit": {
      "states": ["draft-clean", "draft-dirty", "saving", "saved"],
      "transitions": { "add-craft/save-member/cancel-edit": "field edits set dirty; save-member validates name non-empty then persists; cancel-edit discards" },
      "validation": ["name required (non-empty after trim)", "phone optional but if present must be digits-only-ish"]
    },
    "dormant": {
      "states": ["dormant", "reminded"],
      "transitions": { "remind-member": "dormant -> reminded (remindedAt=now); re-detect recomputes on threshold change" }
    }
  },
  "interactionFlows": [
    {
      "id": "flow-add-member",
      "trigger": "navigate-member-add (members-add-button / home-quick-add-member)",
      "steps": ["open member-edit-page in create mode (empty MemberForm)", "user fills name/phone/birthday/level/note + crafts", "add-craft appends craft name to form.crafts", "save-member validates + persists new Member (points=0, createdAt=now, lastVisitAt=0)"],
      "sideEffects": ["DataStore.persist(members)", "navigate back to members-page"],
      "errorPath": "name empty -> disable save / show validation; do not persist"
    },
    {
      "id": "flow-checkin",
      "trigger": "member-checkin / open-checkin-sheet",
      "steps": ["resolve memberId", "PointsService.checkin -> delta=pointsPerCheckin, balanceAfter=member.points+delta", "set member.lastVisitAt=now", "clear member.remindedAt (now active)"],
      "sideEffects": ["write PointsRecord(type=checkin)", "persist members+points"],
      "expectedState": "member.points increased; new record appears in member-history & points-list"
    },
    {
      "id": "flow-consume-points",
      "trigger": "open-points-adjust (points-add-button)",
      "steps": ["open adjust sheet: type (consume/adjust), amount(yuan) or delta, note", "consume: delta=floor(amount*pointsPerYuan); adjust: delta=entered signed value", "apply via PointsService"],
      "sideEffects": ["write PointsRecord", "consume also updates lastVisitAt", "persist"],
      "errorPath": "adjust would make points<0 -> clamp at 0, record actual applied delta"
    },
    {
      "id": "flow-book-course",
      "trigger": "book-course (course-book-button)",
      "steps": ["resolve courseId+memberId", "guard: not already in roster; capacity available", "push memberId to bookedMemberIds", "for each CourseMaterial: InventoryService.deduct(itemId, quantity, refType='course', refId=courseId, reason=title)"],
      "sideEffects": ["persist courses + inventory + inventoryRecords"],
      "expectedState": "course-capacity.booked+1; roster shows member; inventory reduced + records written",
      "errorPath": "capacity-exceeded -> reject, show message; already-booked -> reject"
    },
    {
      "id": "flow-cancel-course",
      "trigger": "cancel-course (course-cancel-button)",
      "steps": ["remove memberId from bookedMemberIds (no inventory auto-restock this phase)"],
      "sideEffects": ["persist courses"]
    },
    {
      "id": "flow-dormant",
      "trigger": "navigate-dormant (home-dormant-button) + auto on home render",
      "steps": ["DormantService.detect(dormantThresholdDays) -> list with days-since & lastVisit", "remind-member sets remindedAt=now"],
      "sideEffects": ["persist members (remindedAt)"],
      "expectedState": "home-dormant-alert shows count; dormant-list populated; reminded members marked"
    },
    {
      "id": "flow-inventory-restock",
      "trigger": "restock-item (inventory-restock-button)",
      "steps": ["open restock input qty+reason", "InventoryService.restock(itemId, qty, reason) -> stock+=qty, write InventoryRecord(delta=+qty, refType='restock')"],
      "sideEffects": ["persist inventory+records"]
    },
    {
      "id": "flow-calendar-nav",
      "trigger": "calendar-prev/next/today + toggle-calendar-view",
      "steps": ["shift cursor month/week/day; recompute calendar/days + calendar/courses for selected range"],
      "expectedState": "calendar-grid + calendar-course-list reflect new range"
    }
  ],
  "testTargets": {
    "navigation": ["tab-home", "tab-members", "tab-courses", "tab-inventory", "tab-profile", "app-root"],
    "actions": [
      "home-checkin-button", "home-points-button", "home-dormant-button", "home-quick-add-member",
      "members-add-button", "member-edit-save", "member-edit-cancel", "member-edit-craft-input",
      "member-checkin-button", "member-points-button", "member-add-work-button", "member-edit-button",
      "points-add-button", "course-book-button", "course-cancel-button", "calendar-prev", "calendar-next",
      "calendar-today", "calendar-add-course", "dormant-remind-button", "inventory-add-button",
      "inventory-restock-button", "inventory-records-button"
    ],
    "inputs": [
      "home-search-input", "members-search-input", "members-filter-craft", "member-edit-name",
