export type InventoryRefType = 'course' | 'consume' | 'restock' | 'manual';
export type CalendarView = 'month' | 'week' | 'day';

export interface Craft {
  id: string;
  name: string;
}

export interface WorkPhoto {
  id: string;
  memberId: string;
  path: string;
  note: string;
  createdAt: number;
}

export interface PointsRecord {
  id: string;
  memberId: string;
  delta: number;
  balanceAfter: number;
  type: PointsType;
  amount: number;
  note: string;
  createdAt: number;
}

export interface CourseMaterial {
  itemId: string;
  quantity: number;
}

export interface Course {
  id: string;
  title: string;
  date: string;
  startTime: string;
  durationMin: number;
  capacity: number;
  bookedMemberIds: string[];
  materialLinks: CourseMaterial[];
  status: CourseStatus;
  note: string;
}

export interface InventoryItem {
  id: string;
  name: string;
  unit: string;
  stock: number;
  threshold: number;
  createdAt: number;
}

export interface InventoryRecord {
  id: string;
  itemId: string;
  delta: number;
  stockAfter: number;
  reason: string;
  refType: InventoryRefType;
  refId: string;
  createdAt: number;
}

export interface Member {
  id: string;
  name: string;
  phone: string;
  birthday: string;
  level: MemberLevel;
  note: string;
  crafts: string[];
  points: number;
  lastVisitAt: number;
  remindedAt: number;
  createdAt: number;
}

export interface Settings {
  studioName: string;
  pointsPerCheckin: number;
  pointsPerYuan: number;
  dormantThresholdDays: number;
}

export interface MemberForm {
  id: string;
  name: string;
  phone: string;
  birthday: string;
  level: MemberLevel;
  note: string;
  crafts: string[];
}

export interface DormantInfo {
  member: Member;
  daysSince: number;
  lastVisitLabel: string;
  reminded: boolean;
}

export interface CourseCapacity {
  booked: number;
  capacity: number;
  remaining: number;
  isFull: boolean;
}

export interface CalendarDay {
  date: string;
  dayNumber: number;
  inMonth: boolean;
  isToday: boolean;
  courseCount: number;
}

export const LEVEL_LABELS: Record<string, string> = {
  'new': '新会员',
  'silver': '银卡',
  'gold': '金卡',
  'platinum': '铂金',
};

export const POINTS_TYPE_LABELS: Record<string, string> = {
  'checkin': '签到',
  'consume': '消费',
  'adjust': '调整',
  'course': '课程',
  'redeem': '兑换',
};

export function levelLabel(level: MemberLevel): string {
  if (level === 'new') {
    return '新会员';
  } else if (level === 'silver') {
    return '银卡';
  } else if (level === 'gold') {
    return '金卡';
  } else if (level === 'platinum') {
    return '铂金';
  }
  return '新会员';
}

export function pointsTypeLabel(type: PointsType): string {
  if (type === 'checkin') {
    return '签到';
  } else if (type === 'consume') {
    return '消费';
  } else if (type === 'adjust') {
    return '调整';
  } else if (type === 'course') {
    return '课程';
  } else if (type === 'redeem') {
    return '兑换';
  }
  return '调整';
}

export function defaultSettings(): Settings {
  const s: Settings = {
    studioName: '我的手作工作室',
    pointsPerCheckin: 10,
    pointsPerYuan: 1,
    dormantThresholdDays: 60,
  };
  return s;
}

export function emptyMemberForm(): MemberForm {
  const f: MemberForm = {
    id: '',
    name: '',
    phone: '',
    birthday: '',
    level: 'new',
    note: '',
    crafts: [],
  };
  return f;
}

export function memberToForm(m: Member): MemberForm {
  const f: MemberForm = {
    id: m.id,
    name: m.name,
    phone: m.phone,
    birthday: m.birthday,
    level: m.level,
    note: m.note,
    crafts: m.crafts,
  };
  return f;
}

export function courseCapacityOf(c: Course): CourseCapacity {
  const booked: number = c.bookedMemberIds.length;
  const remaining: number = c.capacity - booked;
  const cap: CourseCapacity = {
    booked: booked,
    capacity: c.capacity,
    remaining: remaining > 0 ? remaining : 0,
    isFull: booked >= c.capacity && c.capacity > 0,
  };
  return cap;
}

