// MemberService.ets
//
// Member CRUD, craft tag management, work-photo management, and list/search/filter.

import { store } from './DataStore';
import { Member, MemberForm, WorkPhoto } from '../model/Models';

class MemberService {
  list(): Member[] {
    return store.members;
  }

  getById(id: string): Member | null {
    for (let i: number = 0; i < store.members.length; i++) {
      if (store.members[i].id === id) {
        return store.members[i];
      }
    }
    return null;
  }

  search(query: string, craftFilter: string): Member[] {
    const q: string = query.trim();
    const c: string = craftFilter.trim();
    const result: Member[] = [];
    for (let i: number = 0; i < store.members.length; i++) {
      const m: Member = store.members[i];
      if (q.length > 0 && m.name.indexOf(q) < 0 && m.phone.indexOf(q) < 0) {
        continue;
      }
      if (c.length > 0 && !this.hasCraft(m, c)) {
        continue;
      }
      result.push(m);
    }
    return result;
  }

  private hasCraft(m: Member, craft: string): boolean {
    for (let i: number = 0; i < m.crafts.length; i++) {
      if (m.crafts[i] === craft) {
        return true;
      }
    }
    return false;
  }

  allCrafts(): string[] {
    const seen: string[] = [];
    for (let i: number = 0; i < store.members.length; i++) {
      const crafts: string[] = store.members[i].crafts;
      for (let j: number = 0; j < crafts.length; j++) {
        const name: string = crafts[j];
        if (!this.containsString(seen, name)) {
          seen.push(name);
        }
      }
    }
    return seen;
  }

  private containsString(arr: string[], v: string): boolean {
    for (let i: number = 0; i < arr.length; i++) {
      if (arr[i] === v) {
        return true;
      }
    }
    return false;
  }

  // Returns validation error message, or '' on success.
  saveFromForm(form: MemberForm): string {
    const name: string = form.name.trim();
    if (name.length === 0) {
      return '请填写会员姓名';
    }
    if (form.id.length === 0) {
      this.create(name, form.phone.trim(), form.birthday.trim(), form.level, form.note.trim(), this.copyCrafts(form.crafts));
      return '';
    }
    const existing: Member | null = this.getById(form.id);
    if (existing === null) {
      return '会员不存在';
    }
    existing.name = name;
    existing.phone = form.phone.trim();
    existing.birthday = form.birthday.trim();
    existing.level = form.level;
    existing.note = form.note.trim();
    existing.crafts = this.copyCrafts(form.crafts);
    store.persistMembers();
    return '';
  }

  private copyCrafts(src: string[]): string[] {
    const out: string[] = [];
    for (let i: number = 0; i < src.length; i++) {
      out.push(src[i]);
    }
    return out;
  }

  private create(name: string, phone: string, birthday: string, level: Member['level'], note: string, crafts: string[]): Member {
    const m: Member = {
      id: store.nextId('m_'),
      name: name,
      phone: phone,
      birthday: birthday,
      level: level,
      note: note,
      crafts: crafts,
      points: 0,
      lastVisitAt: 0,
      remindedAt: 0,
      createdAt: store.now(),
    };
    store.members.push(m);
    store.persistMembers();
    return m;
  }

  delete(id: string): void {
    const next: Member[] = [];
    for (let i: number = 0; i < store.members.length; i++) {
      if (store.members[i].id !== id) {
        next.push(store.members[i]);
      }
    }
    store.members = next;
    store.persistMembers();
  }

  addCraft(memberId: string, craft: string): void {
    const m: Member | null = this.getById(memberId);
    const name: string = craft.trim();
    if (m === null || name.length === 0) {
      return;
    }
    if (!this.hasCraft(m, name)) {
      m.crafts.push(name);
      store.persistMembers();
    }
  }

  removeCraft(memberId: string, craft: string): void {
    const m: Member | null = this.getById(memberId);
    if (m === null) {
      return;
    }
    const next: string[] = [];
    for (let i: number = 0; i < m.crafts.length; i++) {
      if (m.crafts[i] !== craft) {
        next.push(m.crafts[i]);
      }
    }
    m.crafts = next;
    store.persistMembers();
  }

  addWork(memberId: string, path: string, note: string): WorkPhoto | null {
    const m: Member | null = this.getById(memberId);
    if (m === null) {
      return null;
    }
    const w: WorkPhoto = {
      id: store.nextId('w_'),
      memberId: memberId,
      path: path,
      note: note,
      createdAt: store.now(),
    };
    store.works.push(w);
    store.persistWorks();
    return w;
  }

  worksOf(memberId: string): WorkPhoto[] {
    const out: WorkPhoto[] = [];
    for (let i: number = 0; i < store.works.length; i++) {
      if (store.works[i].memberId === memberId) {
        out.push(store.works[i]);
      }
    }
    return out;
  }
}

export const memberService: MemberService = new MemberService();

