// PointsService.ets
//
// Points ledger: checkin / consume / adjust. Each operation writes a PointsRecord
// (with running balanceAfter) and updates member.points. checkin & consume also
// refresh lastVisitAt and clear remindedAt (member is now active).

import { store } from './DataStore';
import { memberService } from './MemberService';
import { Member, PointsRecord, PointsType } from '../model/Models';

class PointsService {
  recordsOf(memberId: string): PointsRecord[] {
    const out: PointsRecord[] = [];
    for (let i: number = 0; i < store.pointsRecords.length; i++) {
      if (store.pointsRecords[i].memberId === memberId) {
        out.push(store.pointsRecords[i]);
      }
    }
    out.sort((a: PointsRecord, b: PointsRecord) => b.createdAt - a.createdAt);
    return out;
  }

  recordsByType(memberId: string, typeFilter: string): PointsRecord[] {
    const all: PointsRecord[] = this.recordsOf(memberId);
    if (typeFilter === 'all' || typeFilter.length === 0) {
      return all;
    }
    const out: PointsRecord[] = [];
    for (let i: number = 0; i < all.length; i++) {
      if (all[i].type === typeFilter) {
        out.push(all[i]);
      }
    }
    return out;
  }

  checkin(memberId: string): PointsRecord | null {
    const m: Member | null = memberService.getById(memberId);
    if (m === null) {
      return null;
    }
    const delta: number = store.settings.pointsPerCheckin;
    return this.apply(m, delta, 'checkin', 0, '到店签到', true);
  }

  consume(memberId: string, yuan: number, note: string): PointsRecord | null {
    const m: Member | null = memberService.getById(memberId);
    if (m === null || yuan <= 0) {
      return null;
    }
    const delta: number = Math.floor(yuan * store.settings.pointsPerYuan);
    const label: string = note.trim().length > 0 ? note.trim() : `消费 ¥${yuan}`;
    return this.apply(m, delta, 'consume', yuan, label, true);
  }

  adjust(memberId: string, delta: number, note: string): PointsRecord | null {
    const m: Member | null = memberService.getById(memberId);
    if (m === null) {
      return null;
    }
    const label: string = note.trim().length > 0 ? note.trim() : '积分调整';
    // Adjust does NOT count as a visit.
    return this.apply(m, delta, 'adjust', 0, label, false);
  }

  // Core ledger writer. Clamps balance at 0 (delta applied may be reduced).
  apply(m: Member, requestedDelta: number, type: PointsType, amount: number, note: string, countsAsVisit: boolean): PointsRecord {
    let delta: number = requestedDelta;
    if (m.points + delta < 0) {
      delta = -m.points;
    }
    const balanceAfter: number = m.points + delta;
    m.points = balanceAfter;
    if (countsAsVisit) {
      m.lastVisitAt = store.now();
      m.remindedAt = 0;
    }
    const rec: PointsRecord = {
      id: store.nextId('p_'),
      memberId: m.id,
      delta: delta,
      balanceAfter: balanceAfter,
      type: type,
      amount: amount,
      note: note,
      createdAt: store.now(),
    };
    store.pointsRecords.push(rec);
    store.persistMembers();
    store.persistPoints();
    return rec;
  }
}

export const pointsService: PointsService = new PointsService();

