// InventoryService.ets
//
// Consumables stock: create/update items, restock, deduct (floored at 0), and
// movement records. Deduction is invoked by CourseService when a booking consumes
// linked materials, and may be used directly for consume-based deduction.

import { store } from './DataStore';
import { InventoryItem, InventoryRecord, InventoryRefType } from '../model/Models';

class InventoryService {
  list(): InventoryItem[] {
    return store.inventory;
  }

  getById(id: string): InventoryItem | null {
    for (let i: number = 0; i < store.inventory.length; i++) {
      if (store.inventory[i].id === id) {
        return store.inventory[i];
      }
    }
    return null;
  }

  search(query: string): InventoryItem[] {
    const q: string = query.trim();
    if (q.length === 0) {
      return store.inventory;
    }
    const out: InventoryItem[] = [];
    for (let i: number = 0; i < store.inventory.length; i++) {
      if (store.inventory[i].name.indexOf(q) >= 0) {
        out.push(store.inventory[i]);
      }
    }
    return out;
  }

  create(name: string, unit: string, stock: number, threshold: number): InventoryItem {
    const item: InventoryItem = {
      id: store.nextId('i_'),
      name: name.trim(),
      unit: unit.trim().length > 0 ? unit.trim() : '件',
      stock: stock > 0 ? stock : 0,
      threshold: threshold > 0 ? threshold : 0,
      createdAt: store.now(),
    };
    store.inventory.push(item);
    store.persistInventory();
    if (item.stock > 0) {
      this.writeRecord(item, item.stock, '初始化入库', 'restock', '');
    }
    return item;
  }

  update(id: string, name: string, unit: string, threshold: number): void {
    const item: InventoryItem | null = this.getById(id);
    if (item === null) {
      return;
    }
    item.name = name.trim();
    item.unit = unit.trim().length > 0 ? unit.trim() : item.unit;
    item.threshold = threshold > 0 ? threshold : 0;
    store.persistInventory();
  }

  restock(id: string, qty: number, reason: string): InventoryRecord | null {
    const item: InventoryItem | null = this.getById(id);
    if (item === null || qty <= 0) {
      return null;
    }
    item.stock += qty;
    store.persistInventory();
    return this.writeRecord(item, qty, reason.trim().length > 0 ? reason.trim() : '入库补货', 'restock', '');
  }

  // Deduct quantity; floors stock at 0 and records the actually-applied delta.
  // Returns null if item missing or already empty; otherwise the record.
  deduct(id: string, qty: number, refType: InventoryRefType, refId: string, reason: string): InventoryRecord | null {
    const item: InventoryItem | null = this.getById(id);
    if (item === null || qty <= 0) {
      return null;
    }
    let applied: number = qty;
    if (applied > item.stock) {
      applied = item.stock;
    }
    if (applied <= 0) {
      return null;
    }
    item.stock -= applied;
    store.persistInventory();
    return this.writeRecord(item, -applied, reason, refType, refId);
  }

  recordsOf(id: string): InventoryRecord[] {
    const out: InventoryRecord[] = [];
    for (let i: number = 0; i < store.inventoryRecords.length; i++) {
      if (store.inventoryRecords[i].itemId === id) {
        out.push(store.inventoryRecords[i]);
      }
    }
    out.sort((a: InventoryRecord, b: InventoryRecord) => b.createdAt - a.createdAt);
    return out;
  }

  private writeRecord(item: InventoryItem, delta: number, reason: string, refType: InventoryRefType, refId: string): InventoryRecord {
    const rec: InventoryRecord = {
      id: store.nextId('r_'),
      itemId: item.id,
      delta: delta,
      stockAfter: item.stock,
      reason: reason,
      refType: refType,
      refId: refId,
      createdAt: store.now(),
    };
    store.inventoryRecords.push(rec);
    store.persistInventoryRecords();
    return rec;
  }
}

export const inventoryService: InventoryService = new InventoryService();

