// CourseService.ets
//
// Course scheduling + booking. Booking enforces capacity, prevents duplicates,
// and deducts linked materials via InventoryService. Calendar day generation
// supports month/week/day views.

import { store } from './DataStore';
import { inventoryService } from './InventoryService';
import {
  Course, CourseMaterial, CourseCapacity, CourseStatus, CalendarDay, CalendarView, courseCapacityOf,
} from '../model/Models';

class CourseService {
  list(): Course[] {
    return store.courses;
  }

  getById(id: string): Course | null {
    for (let i: number = 0; i < store.courses.length; i++) {
      if (store.courses[i].id === id) {
        return store.courses[i];
      }
    }
    return null;
  }

  coursesOnDate(date: string): Course[] {
    const out: Course[] = [];
    for (let i: number = 0; i < store.courses.length; i++) {
      if (store.courses[i].date === date) {
        out.push(store.courses[i]);
      }
    }
    out.sort((a: Course, b: Course) => a.startTime.localeCompare(b.startTime));
    return out;
  }

  capacity(c: Course): CourseCapacity {
    return courseCapacityOf(c);
  }

  create(
    title: string, date: string, startTime: string, durationMin: number, capacity: number,
    materialLinks: CourseMaterial[], note: string,
  ): Course {
    const c: Course = {
      id: store.nextId('c_'),
      title: title.trim(),
      date: date,
      startTime: startTime,
      durationMin: durationMin > 0 ? durationMin : 60,
      capacity: capacity > 0 ? capacity : 1,
      bookedMemberIds: [],
      materialLinks: materialLinks,
      status: 'open',
      note: note.trim(),
    };
    store.courses.push(c);
    store.persistCourses();
    return c;
  }

  update(id: string, title: string, date: string, startTime: string, durationMin: number, capacity: number, note: string): void {
    const c: Course | null = this.getById(id);
    if (c === null) {
      return;
    }
    c.title = title.trim();
    c.date = date;
    c.startTime = startTime;
    c.durationMin = durationMin > 0 ? durationMin : c.durationMin;
    if (capacity > 0 && capacity < c.bookedMemberIds.length) {
      c.capacity = c.bookedMemberIds.length;
    } else if (capacity > 0) {
      c.capacity = capacity;
    }
    c.note = note.trim();
    this.refreshStatus(c);
    store.persistCourses();
  }

  delete(id: string): void {
    const next: Course[] = [];
    for (let i: number = 0; i < store.courses.length; i++) {
      if (store.courses[i].id !== id) {
        next.push(store.courses[i]);
      }
    }
    store.courses = next;
    store.persistCourses();
  }

  // Returns error message, or '' on success.
  book(courseId: string, memberId: string): string {
    const c: Course | null = this.getById(courseId);
    if (c === null) {
      return '课程不存在';
    }
    if (c.status === 'cancelled') {
      return '课程已取消';
    }
    if (this.isBooked(c, memberId)) {
      return '该会员已预约';
    }
    if (c.bookedMemberIds.length >= c.capacity) {
      return '名额已满';
    }
    c.bookedMemberIds.push(memberId);
    this.refreshStatus(c);
    // Deduct linked materials once per booking.
    for (let i: number = 0; i < c.materialLinks.length; i++) {
      const link: CourseMaterial = c.materialLinks[i];
      inventoryService.deduct(link.itemId, link.quantity, 'course', c.id, `${c.title} 预约扣料`);
    }
    store.persistCourses();
    return '';
  }

  cancel(courseId: string, memberId: string): string {
    const c: Course | null = this.getById(courseId);
    if (c === null) {
      return '课程不存在';
    }
    if (!this.isBooked(c, memberId)) {
      return '该会员未预约';
    }
    const next: string[] = [];
    for (let i: number = 0; i < c.bookedMemberIds.length; i++) {
      if (c.bookedMemberIds[i] !== memberId) {
        next.push(c.bookedMemberIds[i]);
      }
    }
    c.bookedMemberIds = next;
    // Note: inventory is not auto-restocked on cancel this phase.
    this.refreshStatus(c);
    store.persistCourses();
    return '';
  }

  isBooked(c: Course, memberId: string): boolean {
    for (let i: number = 0; i < c.bookedMemberIds.length; i++) {
      if (c.bookedMemberIds[i] === memberId) {
        return true;
      }
    }
    return false;
  }

  private refreshStatus(c: Course): void {
    if (c.status === 'cancelled' || c.status === 'finished') {
      return;
    }
    const newStatus: CourseStatus = c.bookedMemberIds.length >= c.capacity ? 'full' : 'open';
    c.status = newStatus;
  }

  // ---- Calendar grid generation ----

  todayStr(): string {
    return this.formatYMD(new Date());
  }

  formatYMD(d: Date): string {
    const y: number = d.getFullYear();
    const m: number = d.getMonth() + 1;
    const day: number = d.getDate();
    return `${y}-${m < 10 ? '0' : ''}${m}-${day < 10 ? '0' : ''}${day}`;
  }

  // Returns the CalendarDay cells for a month grid (with leading/trailing days
  // from adjacent months so the grid stays rectangular). Each cell carries the
  // count of courses scheduled on that date.
  monthDays(year: number, month0: number): CalendarDay[] {
    const today: string = this.todayStr();
    const first: Date = new Date(year, month0, 1);
    const startWeekday: number = first.getDay();
    const start: Date = new Date(year, month0, 1 - startWeekday);
    const cells: CalendarDay[] = [];
    for (let i: number = 0; i < 42; i++) {
      const d: Date = new Date(start.getFullYear(), start.getMonth(), start.getDate() + i);
      const dateStr: string = this.formatYMD(d);
      const inMonth: boolean = d.getMonth() === month0;
      const cell: CalendarDay = {
        date: dateStr,
        dayNumber: d.getDate(),
        inMonth: inMonth,
        isToday: dateStr === today,
        courseCount: this.countCoursesOn(dateStr),
      };
      cells.push(cell);
    }
    return cells;
  }

  // Seven days centered on the cursor date for the week view.
  weekDays(cursor: Date): CalendarDay[] {
    const today: string = this.todayStr();
    const weekday: number = cursor.getDay();
    const start: Date = new Date(cursor.getFullYear(), cursor.getMonth(), cursor.getDate() - weekday);
    const cells: CalendarDay[] = [];
    for (let i: number = 0; i < 7; i++) {
      const d: Date = new Date(start.getFullYear(), start.getMonth(), start.getDate() + i);
      const dateStr: string = this.formatYMD(d);
      const cell: CalendarDay = {
        date: dateStr,
        dayNumber: d.getDate(),
        inMonth: true,
        isToday: dateStr === today,
        courseCount: this.countCoursesOn(dateStr),
      };
      cells.push(cell);
    }
    return cells;
  }

  private countCoursesOn(date: string): number {
    let n: number = 0;
    for (let i: number = 0; i < store.courses.length; i++) {
      if (store.courses[i].date === date) {
        n += 1;
      }
    }
    return n;
  }
}

export const courseService: CourseService = new CourseService();

