// DormantService.ets
//
// Detects members whose last visit is older than the configured threshold and
// surfaces them with day-since-visit metadata. Reminding marks remindedAt.

import { store } from './DataStore';
import { memberService } from './MemberService';
import { DormantInfo, Member } from '../model/Models';

const DAY_MS: number = 24 * 60 * 60 * 1000;

class DormantService {
  detect(): DormantInfo[] {
    const thresholdDays: number = store.settings.dormantThresholdDays;
    const thresholdMs: number = thresholdDays * DAY_MS;
    const now: number = store.now();
    const out: DormantInfo[] = [];
    for (let i: number = 0; i < store.members.length; i++) {
      const m: Member = store.members[i];
      if (m.lastVisitAt <= 0) {
        // Never visited — treat creation age as the dormancy signal.
        const sinceCreate: number = now - m.createdAt;
        if (sinceCreate > thresholdMs) {
          out.push(this.toInfo(m, sinceCreate));
        }
        continue;
      }
      const elapsed: number = now - m.lastVisitAt;
      if (elapsed > thresholdMs) {
        out.push(this.toInfo(m, elapsed));
      }
    }
    out.sort((a: DormantInfo, b: DormantInfo) => b.daysSince - a.daysSince);
    return out;
  }

  count(): number {
    return this.detect().length;
  }

  remind(memberId: string): void {
    const m: Member | null = memberService.getById(memberId);
    if (m === null) {
      return;
    }
    m.remindedAt = store.now();
    store.persistMembers();
  }

  private toInfo(m: Member, elapsedMs: number): DormantInfo {
    const days: number = Math.floor(elapsedMs / DAY_MS);
    const info: DormantInfo = {
      member: m,
      daysSince: days,
      lastVisitLabel: m.lastVisitAt > 0 ? `${days} 天未到店` : '从未到店',
      reminded: m.remindedAt > 0,
    };
    return info;
  }
}

export const dormantService: DormantService = new DormantService();

