// threshold). Backed by DataStore.settings.

import { store } from './DataStore';
import { Settings } from '../model/Models';

class SettingsService {
  get(): Settings {
    return store.settings;
  }

  updateStudioName(name: string): void {
    const trimmed: string = name.trim();
    store.settings.studioName = trimmed.length > 0 ? trimmed : store.settings.studioName;
    store.persistSettings();
  }

  updatePointsPerCheckin(value: number): void {
    if (value >= 0) {
      store.settings.pointsPerCheckin = Math.floor(value);
      store.persistSettings();
    }
  }

  updatePointsPerYuan(value: number): void {
    if (value >= 0) {
      store.settings.pointsPerYuan = value;
      store.persistSettings();
    }
  }

  updateDormantThresholdDays(days: number): void {
    if (days > 0) {
      store.settings.dormantThresholdDays = Math.floor(days);
      store.persistSettings();
    }
  }
}

export const settingsService: SettingsService = new SettingsService();

