    const err: string = memberService.saveFromForm(this.memberForm);
    if (err.length > 0) {
      this.lastMessage = err;
      return err;
    }
    this.lastMessage = this.memberForm.id.length === 0 ? '已新增会员' : '已保存';
    return '';
  }

  addWorkToSelected(path: string, note: string): void {
    if (this.selectedMemberId.length === 0) {
      return;
    }
    memberService.addWork(this.selectedMemberId, path, note);
  }

  // ---- Points ----

  checkin(memberId: string): void {
    const rec: PointsRecord | null = pointsService.checkin(memberId);
    this.lastMessage = rec !== null ? `签到成功 +${rec.delta}` : '签到失败';
  }

  consume(memberId: string, yuan: number, note: string): void {
    const rec: PointsRecord | null = pointsService.consume(memberId, yuan, note);
    this.lastMessage = rec !== null ? `消费记录 +${rec.delta}` : '消费无效';
  }

  adjustPoints(memberId: string, delta: number, note: string): void {
    const rec: PointsRecord | null = pointsService.adjust(memberId, delta, note);
    this.lastMessage = rec !== null ? `积分已调整 ${rec.delta >= 0 ? '+' : ''}${rec.delta}` : '调整失败';
  }

  pointsRecords(memberId: string, typeFilter: string): PointsRecord[] {
    return pointsService.recordsByType(memberId, typeFilter);
  }

  // ---- Courses ----

  courses(): Course[] {
    return courseService.list();
  }

  selectedCourse(): Course | null {
    return this.selectedCourseId.length > 0 ? courseService.getById(this.selectedCourseId) : null;
  }

  todayCourses(): Course[] {
    return courseService.coursesOnDate(courseService.todayStr());
  }

  bookCourse(courseId: string, memberId: string): string {
    const err: string = courseService.book(courseId, memberId);
    this.lastMessage = err.length > 0 ? err : '预约成功';
    return err;
  }

  cancelCourse(courseId: string, memberId: string): string {
    const err: string = courseService.cancel(courseId, memberId);
    this.lastMessage = err.length > 0 ? err : '已取消预约';
    return err;
  }

  // ---- Calendar ----

  setCalendarView(view: CalendarView): void {
    this.calendarView = view;
  }

  calendarPrev(): void {
    this.shiftCursor(-1);
  }

  calendarNext(): void {
    this.shiftCursor(1);
  }

  calendarToday(): void {
    this.cursor = new Date();
  }

  private shiftCursor(direction: number): void {
    if (this.calendarView === 'month') {
      this.cursor = new Date(this.cursor.getFullYear(), this.cursor.getMonth() + direction, 1);
    } else if (this.calendarView === 'week') {
      this.cursor = new Date(this.cursor.getFullYear(), this.cursor.getMonth(), this.cursor.getDate() + direction * 7);
    } else {
      this.cursor = new Date(this.cursor.getFullYear(), this.cursor.getMonth(), this.cursor.getDate() + direction);
    }
  }

  calendarDays(): CalendarDay[] {
    if (this.calendarView === 'month') {
      return courseService.monthDays(this.cursor.getFullYear(), this.cursor.getMonth());
    } else if (this.calendarView === 'week') {
      return courseService.weekDays(this.cursor);
    }
    const today: string = courseService.todayStr();
    const d: Date = this.cursor;
    const dateStr: string = courseService.formatYMD(d);
    const cell: CalendarDay = {
      date: dateStr,
      dayNumber: d.getDate(),
      inMonth: true,
      isToday: dateStr === today,
      courseCount: courseService.coursesOnDate(dateStr).length,
    };
    const arr: CalendarDay[] = [cell];
    return arr;
  }

  coursesOnCursor(): Course[] {
    if (this.calendarView === 'day') {
      return courseService.coursesOnDate(courseService.formatYMD(this.cursor));
    }
    // For month/week, return courses whose date falls within the visible range.
    const days: CalendarDay[] = this.calendarDays();
    const dates: string[] = [];
    for (let i: number = 0; i < days.length; i++) {
      dates.push(days[i].date);
    }
    const out: Course[] = [];
    const all: Course[] = courseService.list();
    for (let i: number = 0; i < all.length; i++) {
      if (this.containsString(dates, all[i].date)) {
        out.push(all[i]);
      }
    }
    out.sort((a: Course, b: Course) => a.date.localeCompare(b.date) || a.startTime.localeCompare(b.startTime));
    return out;
  }

  private containsString(arr: string[], v: string): boolean {
    for (let i: number = 0; i < arr.length; i++) {
      if (arr[i] === v) {
        return true;
      }
    }
    return false;
  }

  // ---- Dormant ----

  dormantList(): DormantInfo[] {
    return dormantService.detect();
  }

  dormantCount(): number {
    return dormantService.count();
  }

  remindMember(memberId: string): void {
    dormantService.remind(memberId);
    this.lastMessage = '已标记为已提醒';
  }

  setDormantThreshold(days: number): void {
    settingsService.updateDormantThresholdDays(days);
    this.lastMessage = `沉睡阈值已设为 ${days} 天`;
  }

  // ---- Inventory ----

  inventory(): InventoryItem[] {
    return inventoryService.list();
  }

  searchInventory(query: string): InventoryItem[] {
    return inventoryService.search(query);
  }

  addInventory(name: string, unit: string, stock: number, threshold: number): void {
    inventoryService.create(name, unit, stock, threshold);
    this.lastMessage = '已新增耗材';
  }

  restock(itemId: string, qty: number, reason: string): void {
    const rec = inventoryService.restock(itemId, qty, reason);
    this.lastMessage = rec !== null ? `已入库 +${rec.delta}` : '入库失败';
  }

  // ---- Settings ----

  studioName(): string {
    return settingsService.get().studioName;
  }

  updateStudioName(name: string): void {
    settingsService.updateStudioName(name);
  }

  settings() {
    return settingsService.get();
  }
}

export const app: AppController = new AppController();

export function ensureStoreReady(): boolean {
  return store.isReady();
}

