// DataStore.ets
//
// Central local-first store for 手作·印记. Singleton holding all entity arrays
// and Settings, persisted to disk via @kit.ArkData preferences (JSON-serialized).
// First launch yields a real empty state — no seeded sample data.
//
// ArkTS strict notes:
// - No spreads; arrays rebuilt with push/loops.
// - JSON.parse results cast explicitly with `as <Type>[]`.
// - IDs come from a persisted monotonic sequence (nextId), not randomness.

import { preferences } from '@kit.ArkData';
import { common } from '@kit.AbilityKit';
import { hilog } from '@kit.PerformanceAnalysisKit';
import {
  Member, WorkPhoto, PointsRecord, Course, InventoryItem, InventoryRecord, Settings, defaultSettings,
} from '../model/Models';

const STORE_NAME: string = 'shouzuo.store';
const TAG: string = 'ShouZuo.DataStore';
const DOMAIN: number = 0x0501;

class DataStore {
  private static instance: DataStore | null = null;

  private ctx: common.Context | null = null;
  private pref: preferences.Preferences | null = null;

  members: Member[] = [];
  works: WorkPhoto[] = [];
  pointsRecords: PointsRecord[] = [];
  courses: Course[] = [];
  inventory: InventoryItem[] = [];
  inventoryRecords: InventoryRecord[] = [];
  settings: Settings = defaultSettings();
  private seq: number = 0;

  private constructor() {}

  static getInstance(): DataStore {
    if (DataStore.instance === null) {
      DataStore.instance = new DataStore();
    }
    return DataStore.instance;
  }

  init(context: common.Context): void {
    this.ctx = context;
    try {
      this.pref = preferences.getPreferencesSync(context, STORE_NAME);
      this.load();
    } catch (err) {
      hilog.error(DOMAIN, TAG, 'init failed: %{public}s', JSON.stringify(err));
    }
  }

  isReady(): boolean {
    return this.pref !== null;
  }

  now(): number {
    return Date.now();
  }

  // Monotonic id generator. Persists the sequence so ids stay unique across runs.
  nextId(prefix: string): string {
    this.seq += 1;
    this.persistSeq();
    return `${prefix}${this.seq}`;
  }

  private load(): void {
    if (this.pref === null) {
      return;
    }
    try {
      this.settings = this.readSettings();
      this.members = this.readArray<Member>('shouzuo.members');
      this.works = this.readArray<WorkPhoto>('shouzuo.works');
      this.pointsRecords = this.readArray<PointsRecord>('shouzuo.points');
      this.courses = this.readArray<Course>('shouzuo.courses');
      this.inventory = this.readArray<InventoryItem>('shouzuo.inventory');
      this.inventoryRecords = this.readArray<InventoryRecord>('shouzuo.inventoryRecords');
      const seqRaw: string = this.pref.getSync('shouzuo.seq', '') as string;
      this.seq = seqRaw === '' ? 0 : Number.parseInt(seqRaw, 10);
      if (Number.isNaN(this.seq)) {
        this.seq = 0;
      }
    } catch (err) {
      hilog.error(DOMAIN, TAG, 'load failed: %{public}s', JSON.stringify(err));
    }
  }

  private readArray<T>(key: string): T[] {
    if (this.pref === null) {
      return [];
    }
    const raw: string = this.pref.getSync(key, '') as string;
    if (raw === '' || raw === null) {
      return [];
    }
    try {
      return JSON.parse(raw) as T[];
    } catch (err) {
      hilog.error(DOMAIN, TAG, 'parse %{public}s failed: %{public}s', key, JSON.stringify(err));
      return [];
    }
  }

  private readSettings(): Settings {
    if (this.pref === null) {
      return defaultSettings();
    }
    const raw: string = this.pref.getSync('shouzuo.settings', '') as string;
    if (raw === '' || raw === null) {
      return defaultSettings();
    }
    try {
      const parsed: Settings = JSON.parse(raw) as Settings;
      const base: Settings = defaultSettings();
      const merged: Settings = {
        studioName: parsed.studioName && parsed.studioName.length > 0 ? parsed.studioName : base.studioName,
        pointsPerCheckin: parsed.pointsPerCheckin > 0 ? parsed.pointsPerCheckin : base.pointsPerCheckin,
        pointsPerYuan: parsed.pointsPerYuan > 0 ? parsed.pointsPerYuan : base.pointsPerYuan,
        dormantThresholdDays: parsed.dormantThresholdDays > 0 ? parsed.dormantThresholdDays : base.dormantThresholdDays,
      };
      return merged;
    } catch (err) {
      return defaultSettings();
    }
  }

  private write(key: string, value: string): void {
    if (this.pref === null) {
      return;
    }
    this.pref.putSync(key, value);
    this.pref.flushSync();
  }

  persistMembers(): void { this.write('shouzuo.members', JSON.stringify(this.members)); }
  persistWorks(): void { this.write('shouzuo.works', JSON.stringify(this.works)); }
  persistPoints(): void { this.write('shouzuo.points', JSON.stringify(this.pointsRecords)); }
  persistCourses(): void { this.write('shouzuo.courses', JSON.stringify(this.courses)); }
  persistInventory(): void { this.write('shouzuo.inventory', JSON.stringify(this.inventory)); }
  persistInventoryRecords(): void { this.write('shouzuo.inventoryRecords', JSON.stringify(this.inventoryRecords)); }
  persistSettings(): void { this.write('shouzuo.settings', JSON.stringify(this.settings)); }
  private persistSeq(): void { this.write('shouzuo.seq', `${this.seq}`); }
}

export const store: DataStore = DataStore.getInstance();

