// DataStore.ets
//
// Central local-first store for 手作·印记. Singleton holding all entity arrays
// and Settings, persisted to disk via @kit.ArkData preferences (JSON-serialized).
// First launch yields a real empty state — no seeded sample data.
//
// ArkTS strict notes:
// - No spreads; arrays rebuilt with push/loops.
// - JSON.parse results cast explicitly with `as <Type>[]`.
// - IDs come from a persisted monotonic sequence (nextId), not randomness.

import { preferences } from '@kit.ArkData';
import { common } from '@kit.AbilityKit';
import { hilog } from '@kit.PerformanceAnalysisKit';
import {
  Member, WorkPhoto, PointsRecord, Course, InventoryItem, InventoryRecord, Settings, defaultSettings,
} from '../model/Models';

const STORE_NAME: string = 'shouzuo.store';
const TAG: string = 'ShouZuo.DataStore';
const DOMAIN: number = 0x0501;

class DataStore {
  private static instance: DataStore | null = null;

  private pref: preferences.Preferences | null = null;

  members: Member[] = [];
  works: WorkPhoto[] = [];
  pointsRecords: PointsRecord[] = [];
  courses: Course[] = [];
  inventory: InventoryItem[] = [];
  inventoryRecords: InventoryRecord[] = [];
  settings: Settings = defaultSettings();
  private seq: number = 0;

  private constructor() {}

  static getInstance(): DataStore {
    if (DataStore.instance === null) {
      DataStore.instance = new DataStore();
    }
    return DataStore.instance;
  }

  init(context: common.Context): void {
    try {
      const opts: preferences.Options = { name: STORE_NAME };
      this.pref = preferences.getPreferencesSync(context, opts);
      this.load();
    } catch (err) {
      hilog.error(DOMAIN, TAG, 'init failed: %{public}s', JSON.stringify(err));
    }
  }

  isReady(): boolean {
    return this.pref !== null;
  }

  now(): number {
    return Date.now();
  }

  // Monotonic id generator. Persists the sequence so ids stay unique across runs.
  nextId(prefix: string): string {
    this.seq += 1;
    this.persistSeq();
    return `${prefix}${this.seq}`;
  }

  private load(): void {
    if (this.pref === null) {
      return;
    }
    try {
      this.settings = this.readSettings();
      this.members = this.readArray<Member>('shouzuo.members');
      this.works = this.readArray<WorkPhoto>('shouzuo.works');
      this.pointsRecords = this.readArray<PointsRecord>('shouzuo.points');
      this.courses = this.readArray<Course>('shouzuo.courses');
      this.inventory = this.readArray<InventoryItem>('shouzuo.inventory');
      this.inventoryRecords = this.readArray<InventoryRecord>('shouzuo.inventoryRecords');
      const seqRaw: string = this.pref.getSync('shouzuo.seq', '') as string;
      this.seq = seqRaw === '' ? 0 : Number.parseInt(seqRaw, 10);
      if (Number.isNaN(this.seq)) {
        this.seq = 0;
      }
    } catch (err) {
      hilog.error(DOMAIN, TAG, 'load failed: %{public}s', JSON.stringify(err));
    }
  }

  private readArray<T>(key: string): T[] {
    if (this.pref === null) {
      return [];
    }
    const raw: string = this.pref.getSync(key, '') as string;
    if (raw === '' || raw === null) {
      return [];
    }
    try {
      return JSON.parse(raw) as T[];
    } catch (err) {
      hilog.error(DOMAIN, TAG, 'parse %{public}s failed: %{public}s', key, JSON.stringify(err));
      return [];
    }
  }

  private readSettings(): Settings {
    if (this.pref === null) {
      return defaultSettings();
    }
    const raw: string = this.pref.getSync('shouzuo.settings', '') as string;
    if (raw === '' || raw === null) {
      return defaultSettings();
    }
    try {
      const parsed: Settings = JSON.parse(raw) as Settings;
      const base: Settings = defaultSettings();
      const merged: Settings = {
        studioName: parsed.studioName && parsed.studioName.length > 0 ? parsed.studioName : base.studioName,
        pointsPerCheckin: parsed.pointsPerCheckin > 0 ? parsed.pointsPerCheckin : base.pointsPerCheckin,
        pointsPerYuan: parsed.pointsPerYuan > 0 ? parsed.pointsPerYuan : base.pointsPerYuan,
        dormantThresholdDays: parsed.dormantThresholdDays > 0 ? parsed.dormantThresholdDays : base.dormantThresholdDays,
      };
      return merged;
    } catch (err) {
      return defaultSettings();
    }
  }

  private write(key: string, value: string): void {
    if (this.pref === null) {
      return;
    }
    this.pref.putSync(key, value);
    this.pref.flushSync();
  }

  persistMembers(): void { this.write('shouzuo.members', JSON.stringify(this.members)); }
  persistWorks(): void { this.write('shouzuo.works', JSON.stringify(this.works)); }
  persistPoints(): void { this.write('shouzuo.points', JSON.stringify(this.pointsRecords)); }
  persistCourses(): void { this.write('shouzuo.courses', JSON.stringify(this.courses)); }
  persistInventory(): void { this.write('shouzuo.inventory', JSON.stringify(this.inventory)); }
  persistInventoryRecords(): void { this.write('shouzuo.inventoryRecords', JSON.stringify(this.inventoryRecords)); }
  persistSettings(): void { this.write('shouzuo.settings', JSON.stringify(this.settings)); }
  private persistSeq(): void { this.write('shouzuo.seq', `${this.seq}`); }
}

export const store: DataStore = DataStore.getInstance();

// MemberService.ets
//
// Member CRUD, craft tag management, work-photo management, and list/search/filter.

import { store } from './DataStore';
import { Member, MemberForm, WorkPhoto } from '../model/Models';

class MemberService {
  list(): Member[] {
    return store.members;
  }

  getById(id: string): Member | null {
    for (let i: number = 0; i < store.members.length; i++) {
      if (store.members[i].id === id) {
        return store.members[i];
      }
    }
    return null;
  }

  search(query: string, craftFilter: string): Member[] {
    const q: string = query.trim();
    const c: string = craftFilter.trim();
    const result: Member[] = [];
    for (let i: number = 0; i < store.members.length; i++) {
      const m: Member = store.members[i];
      if (q.length > 0 && m.name.indexOf(q) < 0 && m.phone.indexOf(q) < 0) {
        continue;
      }
      if (c.length > 0 && !this.hasCraft(m, c)) {
        continue;
      }
      result.push(m);
    }
    return result;
  }

  private hasCraft(m: Member, craft: string): boolean {
    for (let i: number = 0; i < m.crafts.length; i++) {
      if (m.crafts[i] === craft) {
        return true;
      }
    }
    return false;
  }

  allCrafts(): string[] {
    const seen: string[] = [];
    for (let i: number = 0; i < store.members.length; i++) {
      const crafts: string[] = store.members[i].crafts;
      for (let j: number = 0; j < crafts.length; j++) {
        const name: string = crafts[j];
        if (!this.containsString(seen, name)) {
          seen.push(name);
        }
      }
    }
    return seen;
  }

  private containsString(arr: string[], v: string): boolean {
    for (let i: number = 0; i < arr.length; i++) {
      if (arr[i] === v) {
        return true;
      }
    }
    return false;
  }

  // Returns validation error message, or '' on success.
  saveFromForm(form: MemberForm): string {
    const name: string = form.name.trim();
    if (name.length === 0) {
      return '请填写会员姓名';
    }
    if (form.id.length === 0) {
      this.create(name, form.phone.trim(), form.birthday.trim(), form.level, form.note.trim(), this.copyCrafts(form.crafts));
      return '';
    }
    const existing: Member | null = this.getById(form.id);
    if (existing === null) {
      return '会员不存在';
    }
    existing.name = name;
    existing.phone = form.phone.trim();
    existing.birthday = form.birthday.trim();
    existing.level = form.level;
    existing.note = form.note.trim();
    existing.crafts = this.copyCrafts(form.crafts);
    store.persistMembers();
    return '';
  }

  private copyCrafts(src: string[]): string[] {
    const out: string[] = [];
    for (let i: number = 0; i < src.length; i++) {
      out.push(src[i]);
    }
    return out;
  }

  private create(name: string, phone: string, birthday: string, level: Member['level'], note: string, crafts: string[]): Member {
    const m: Member = {
      id: store.nextId('m_'),
      name: name,
      phone: phone,
      birthday: birthday,
      level: level,
      note: note,
      crafts: crafts,
      points: 0,
      lastVisitAt: 0,
      remindedAt: 0,
      createdAt: store.now(),
    };
    store.members.push(m);
    store.persistMembers();
    return m;
  }

  delete(id: string): void {
    const next: Member[] = [];
    for (let i: number = 0; i < store.members.length; i++) {
      if (store.members[i].id !== id) {
        next.push(store.members[i]);
      }
    }
    store.members = next;
    store.persistMembers();
  }

  addCraft(memberId: string, craft: string): void {
    const m: Member | null = this.getById(memberId);
    const name: string = craft.trim();
    if (m === null || name.length === 0) {
      return;
    }
    if (!this.hasCraft(m, name)) {
      m.crafts.push(name);
      store.persistMembers();
    }
  }

  removeCraft(memberId: string, craft: string): void {
    const m: Member | null = this.getById(memberId);
    if (m === null) {
      return;
    }
    const next: string[] = [];
    for (let i: number = 0; i < m.crafts.length; i++) {
      if (m.crafts[i] !== craft) {
        next.push(m.crafts[i]);
      }
    }
    m.crafts = next;
    store.persistMembers();
  }

  addWork(memberId: string, path: string, note: string): WorkPhoto | null {
    const m: Member | null = this.getById(memberId);
    if (m === null) {
      return null;
    }
    const w: WorkPhoto = {
      id: store.nextId('w_'),
      memberId: memberId,
      path: path,
      note: note,
      createdAt: store.now(),
    };
    store.works.push(w);
    store.persistWorks();
    return w;
  }

  worksOf(memberId: string): WorkPhoto[] {
    const out: WorkPhoto[] = [];
    for (let i: number = 0; i < store.works.length; i++) {
      if (store.works[i].memberId === memberId) {
        out.push(store.works[i]);
      }
    }
    return out;
  }
}

