    store.members = next;
    store.persistMembers();
  }

  addCraft(memberId: string, craft: string): void {
    const m: Member | null = this.getById(memberId);
    const name: string = craft.trim();
    if (m === null || name.length === 0) {
      return;
    }
    if (!this.hasCraft(m, name)) {
      m.crafts.push(name);
      store.persistMembers();
    }
  }

  removeCraft(memberId: string, craft: string): void {
    const m: Member | null = this.getById(memberId);
    if (m === null) {
      return;
    }
    const next: string[] = [];
    for (let i: number = 0; i < m.crafts.length; i++) {
      if (m.crafts[i] !== craft) {
        next.push(m.crafts[i]);
      }
    }
    m.crafts = next;
    store.persistMembers();
  }

  addWork(memberId: string, path: string, note: string): WorkPhoto | null {
    const m: Member | null = this.getById(memberId);
    if (m === null) {
      return null;
    }
    const w: WorkPhoto = {
      id: store.nextId('w_'),
      memberId: memberId,
      path: path,
      note: note,
      createdAt: store.now(),
    };
    store.works.push(w);
    store.persistWorks();
    return w;
  }

  worksOf(memberId: string): WorkPhoto[] {
    const out: WorkPhoto[] = [];
    for (let i: number = 0; i < store.works.length; i++) {
      if (store.works[i].memberId === memberId) {
        out.push(store.works[i]);
      }
    }
    return out;
  }
}

export const memberService: MemberService = new MemberService();

